import { createHash } from 'crypto';

interface EvalContext {
  userId: string;
  attributes?: Record<string, string | number | boolean>;
}

interface Rule {
  attribute: string;
  equals: string | number | boolean;
  variation: boolean;
}

interface FlagConfig {
  key: string;
  enabled: boolean;          // master off switch
  individualOn: string[];    // userIds forced on
  rules: Rule[];             // cohort targeting
  rolloutPercent: number;    // 0..100 for the remainder
}

// Deterministic bucketing: hash (flagKey + userId) into a stable 0..99 bucket.
// Same inputs -> same bucket, forever. Salting with the flag key means a user
// is not correlated across different flags (avoids cross-flag bias).
function bucketOf(flagKey: string, userId: string): number {
  const digest = createHash('sha1').update(`${flagKey}:${userId}`).digest();
  // Use the first 4 bytes as an unsigned int, then map to 0..99.
  const n = digest.readUInt32BE(0);
  return n % 100;
}

// Evaluate a flag with targeting + a guaranteed safe default.
function evaluate(
  flag: FlagConfig | undefined,
  ctx: EvalContext,
  defaultValue: boolean,
): boolean {
  try {
    // Cache miss / service outage: config is undefined -> safe default.
    if (!flag) return defaultValue;
    // Master kill switch.
    if (!flag.enabled) return false;
    // 1) Individual overrides win first.
    if (flag.individualOn.includes(ctx.userId)) return true;
    // 2) Cohort rules next.
    for (const rule of flag.rules) {
      if (ctx.attributes?.[rule.attribute] === rule.equals) {
        return rule.variation;
      }
    }
    // 3) Deterministic percentage rollout for everyone else.
    return bucketOf(flag.key, ctx.userId) < flag.rolloutPercent;
  } catch {
    // Any unexpected error must never break the request path.
    return defaultValue;
  }
}

// Usage on a hot path - note the mandatory safe default (false).
const showNewCheckout = evaluate(cache.get('new-checkout'), ctx, false);

// WRONG: client-side flag is the only gate. Trivially bypassed by the user.
if (flags.evaluate('premium-export', ctx, false)) {
  renderExportButton();
}
// Attacker just POSTs /api/export directly -> data leaks.

// RIGHT: the flag controls UX; the SERVER independently enforces entitlement.
app.post('/api/export', (req, res) => {
  if (!req.user.plan.includes('premium')) {
    return res.status(403).json({ error: 'forbidden' });
  }
  // ...perform export
});
// The client flag may still hide the button for a clean UX,
// but authorization is enforced server-side, every time.

