import { createHash } from 'crypto';

interface EvalContext {
  userId: string;
  attributes?: Record<string, string | number | boolean>;
}
interface Rule {
  attribute: string;
  equals: string | number | boolean;
  variation: boolean;
}
interface FlagConfig {
  key: string;
  enabled: boolean;
  individualOn: string[];
  rules: Rule[];
  rolloutPercent: number; // 0..100
}

// Pure, deterministic bucketing: same (flagKey,userId) -> same 0..99 bucket.
export function bucketOf(flagKey: string, userId: string): number {
  const digest = createHash('sha1').update(`${flagKey}:${userId}`).digest();
  return digest.readUInt32BE(0) % 100;
}

export function evaluate(
  flag: FlagConfig | undefined,
  ctx: EvalContext,
  defaultValue: boolean,
): boolean {
  try {
    if (!flag) return defaultValue;              // missing config / outage
    if (!flag.enabled) return false;             // master kill switch
    if (flag.individualOn.includes(ctx.userId))  // individual override
      return true;
    for (const rule of flag.rules) {             // cohort rules
      if (ctx.attributes?.[rule.attribute] === rule.equals) {
        return rule.variation;
      }
    }
    // deterministic percentage rollout for the remainder
    return bucketOf(flag.key, ctx.userId) < flag.rolloutPercent;
  } catch {
    return defaultValue;                         // never break the request path
  }
}

// --- quick sanity checks ---
const flag: FlagConfig = {
  key: 'new-checkout',
  enabled: true,
  individualOn: ['qa-1'],
  rules: [{ attribute: 'plan', equals: 'enterprise', variation: true }],
  rolloutPercent: 10,
};

// stable: same user always same result
const u = { userId: 'user-42' };
console.log(evaluate(flag, u, false) === evaluate(flag, u, false)); // true
// override wins
console.log(evaluate(flag, { userId: 'qa-1' }, false)); // true
// cohort wins over rollout
console.log(evaluate(flag, { userId: 'x', attributes: { plan: 'enterprise' } }, false)); // true
// outage -> safe default
console.log(evaluate(undefined, u, false)); // false

interface Health {
  errorRate: number;   // 0..1
  p99LatencyMs: number;
}
interface Thresholds {
  maxErrorRate: number;
  maxP99Ms: number;
}

class RolloutController {
  // dark -> canary -> ramp -> full
  private readonly stages = [0, 1, 5, 25, 50, 100];
  private stageIndex = 0;
  private killed = false;

  constructor(private readonly thresholds: Thresholds) {}

  get currentPercent(): number {
    return this.killed ? 0 : this.stages[this.stageIndex];
  }

  private healthy(h: Health): boolean {
    return (
      h.errorRate <= this.thresholds.maxErrorRate &&
      h.p99LatencyMs <= this.thresholds.maxP99Ms
    );
  }

  // Operator or automation can force the kill switch at any time.
  kill(reason: string): void {
    this.killed = true;
    console.warn(`KILL SWITCH: payments rollout -> 0% (${reason})`);
  }

  // Call once per soak window with fresh metrics.
  tick(h: Health): number {
    if (this.killed) return 0;
    if (!this.healthy(h)) {
      this.kill(
        `errorRate=${h.errorRate} p99=${h.p99LatencyMs}ms breached threshold`,
      );
      return 0;
    }
    // Healthy: advance one stage if not already at 100%.
    if (this.stageIndex < this.stages.length - 1) {
      this.stageIndex++;
      console.log(`payments rollout advanced -> ${this.currentPercent}%`);
    }
    return this.currentPercent;
  }
}

// --- simulation ---
const rc = new RolloutController({ maxErrorRate: 0.02, maxP99Ms: 400 });
rc.tick({ errorRate: 0.001, p99LatencyMs: 210 }); // -> 1% canary
rc.tick({ errorRate: 0.005, p99LatencyMs: 260 }); // -> 5%
rc.tick({ errorRate: 0.03,  p99LatencyMs: 380 }); // breach -> kill to 0%
console.log('final percent:', rc.currentPercent); // 0
